const body = $json.body ?? $json;
const rawIdea = String(body.raw_idea ?? '').trim();
const capturedAt = String(body.captured_at ?? '').trim();
const source = String(body.source ?? '').trim();
const captureId = String(body.capture_id ?? '').trim();
if (!rawIdea || !capturedAt || !source || !captureId) {
  throw new Error('raw_idea, captured_at, source, and capture_id are required');
}
return [{ json: { raw_idea: rawIdea, captured_at: capturedAt, source, capture_id: captureId } }];

const input = $('Normalize Input').first().json;
const content = $json.choices?.[0]?.message?.content;
if (!content) {
  throw new Error('OpenAI response did not include message content');
}
const parsed = JSON.parse(content);
const processedAt = new Date().toISOString();
const id = `idea-${input.captured_at.replace(/[-:]/g, '').replace('T', '-').replace('Z', '')}-${input.capture_id}`;
return [{ json: { id, raw_idea: input.raw_idea, captured_at: input.captured_at, source: input.source, capture_id: input.capture_id, summary: parsed.summary, tags: parsed.tags, next_steps: parsed.next_steps, provider: 'openai', processed_at: processedAt } }];
